<template><div class="panel"><div class="section-head"><div><h2>模型供应商</h2><p>API Key 加密保存，列表仅显示脱敏值。</p></div><el-button v-if="auth.hasPermission('model:provider:create')" type="primary" @click="open()">新增供应商</el-button></div><el-table :data="rows"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column prop="baseUrl" label="服务地址"/><el-table-column prop="concurrencyLevel" label="并发维度"/><el-table-column prop="concurrencyLimit" label="并发数"/><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?'编辑供应商':'新增供应商'" width="620px"><el-form label-width="100px"><el-form-item label="编码"><el-input v-model="form.code"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="Base URL"><el-input v-model="form.baseUrl"/></el-form-item><el-form-item label="API Keys"><el-input v-model="form.apiKeys" type="textarea" :placeholder="form.id?'留空保留原密钥；多个密钥用逗号或换行分隔':'多个密钥用逗号或换行分隔'"/></el-form-item><el-form-item label="并发维度"><el-select v-model="form.concurrencyLevel"><el-option label="供应商" value="PROVIDER"/><el-option label="API Key" value="API_KEY"/></el-select></el-form-item><el-form-item label="并发数"><el-input-number v-model="form.concurrencyLimit" :min="1"/></el-form-item><el-form-item label="超时秒数"><el-input-number v-model="form.timeoutSeconds" :min="1"/></el-form-item><el-form-item label="启用"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import http from'../api/http';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),rows=ref([]),visible=ref(false),form=reactive({id:null,code:'',name:'',baseUrl:'',apiKeys:'',concurrencyLimit:4,concurrencyLevel:'PROVIDER',timeoutSeconds:60,enabled:true});async function load(){rows.value=(await http.get('/models/providers')).data}/** 打开供应商窗口。 */function open(row){Object.assign(form,row?{...row,apiKeys:''}:{id:null,code:'',name:'',baseUrl:'',apiKeys:'',concurrencyLimit:4,concurrencyLevel:'PROVIDER',timeoutSeconds:60,enabled:true});visible.value=true}/** 保存供应商。 */async function save(){form.id?await http.put(`/models/providers/${form.id}`,form):await http.post('/models/providers',form);visible.value=false;await load();ElMessage.success('保存成功')}/** 删除供应商。 */async function remove(row){await ElMessageBox.confirm(`确认删除供应商「${row.name}」？`);await http.delete(`/models/providers/${row.id}`);await load()}onMounted(load)</script>
